const parts = input.split(/^-{3,}$/m);
if (parts.length < 2) {
  return { output: '', error: 'Could not find delimiter. Separate two text blocks with a line containing only "---".' };
}
const linesA = parts[0].split('\n');
const linesB = parts.slice(1).join('---').split('\n');
// Remove leading/trailing empty lines from each block
while (linesA.length && !linesA[0].trim()) linesA.shift();
while (linesA.length && !linesA[linesA.length-1].trim()) linesA.pop();
while (linesB.length && !linesB[0].trim()) linesB.shift();
while (linesB.length && !linesB[linesB.length-1].trim()) linesB.pop();

const maxLen = Math.max(linesA.length, linesB.length);
const output = [];
let added = 0, removed = 0, changed = 0;
for (let i = 0; i < maxLen; i++) {
  const a = linesA[i];
  const b = linesB[i];
  if (a === undefined) { output.push('+ ' + b); added++; }
  else if (b === undefined) { output.push('- ' + a); removed++; }
  else if (a === b) { output.push('  ' + a); }
  else { output.push('- ' + a); output.push('+ ' + b); changed++; }
}
output.unshift(`@@ -${linesA.length} lines / +${linesB.length} lines  [+${added} added, -${removed} removed, ~${changed} changed] @@`, '');
return { output: output.join('\n'), outputLanguage: 'diff' };
